module nand4bb (
    input  A_N,
    input  B_N,
    input  C  ,
    input  D  ,
    output Y
);

    wire not_nand_result = ~(A_N & B_N & C & D);
    assign Y = not_nand_result;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

endmodule
